instruction:
The classic conditional. Always use braces `{}`:

```cpp
if (score >= 90) {
    cout << "A" << endl;
} else if (score >= 80) {
    cout << "B" << endl;
} else {
    cout << "Below B" << endl;
}
```

Conditions checked top to bottom — first match wins.

starter:
#include <iostream>
using namespace std;

int main() {
    int score = 78;

    if (score >= 90) {
        cout << "A — Excellent!" << endl;
    } else if (score >= 80) {
        cout << "B — Great!" << endl;
    } else if (score >= 70) {
        cout << "C — Solid." << endl;
    } else if (score >= 60) {
        cout << "D — Keep going." << endl;
    } else {
        cout << "F — Try again." << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    bool isAdmin = false;
    bool isVerified = true;
    int age = 20;

    // Access if admin OR (verified AND 18+)
    if (isAdmin || (isVerified && age >= 18)) {
        cout << "Access granted." << endl;
    } else {
        cout << "Access denied." << endl;
    }

    // Short-circuit demo:
    int x = 0;
    if (x != 0 && 10/x > 1) {  // safe — second part never evaluates
        cout << "true" << endl;
    } else {
        cout << "Short-circuited safely." << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int age = 20;
    int score = 55;
    int a = 10, b = 7;

    string status = (age >= 18) ? "adult" : "minor";
    string grade  = (score >= 60) ? "PASS" : "FAIL";
    int    maxVal = (a > b) ? a : b;

    cout << status << endl;
    cout << grade  << endl;
    cout << maxVal << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int day = 3;

    switch (day) {
        case 1: cout << "Monday" << endl;    break;
        case 2: cout << "Tuesday" << endl;   break;
        case 3: cout << "Wednesday" << endl; break;
        case 4: cout << "Thursday" << endl;  break;
        case 5: cout << "Friday" << endl;    break;
        case 6:
        case 7: cout << "Weekend!" << endl;  break;  // fallthrough: 6 and 7
        default: cout << "Invalid" << endl;  break;
    }

    // Switch on char:
    char grade = 'B';
    switch (grade) {
        case 'A': cout << "Excellent" << endl; break;
        case 'B': cout << "Good" << endl;      break;
        case 'C': cout << "Average" << endl;   break;
        default:  cout << "Below average" << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int a = 10, b = 20;

    cout << boolalpha;
    cout << (a == b)  << endl;  // false
    cout << (a != b)  << endl;  // true
    cout << (a < b)   << endl;  // true
    cout << (a >= 10) << endl;  // true

    // Common pitfall:
    int x = 5;
    if (x == 5) {  // correct comparison
        cout << "x is 5" << endl;
    }
    // if (x = 0) would ASSIGN 0 to x and the condition would be false!

    return 0;
}
